import React, { useRef, useState, useMemo } from "react";
import * as XLSX from "xlsx";
import { supabase } from "../supabaseClient";
import "./GelirEkleme.css";

export default function GelirEkleme() {
    const inputRef = useRef(null);
    const [isDragging, setIsDragging] = useState(false);
    const [file, setFile] = useState(null);
    const [error, setError] = useState("");
    const [downloading, setDownloading] = useState(false);

    const allowed = useMemo(() => [".xlsx", ".xls"], []);

    const openPicker = () => inputRef.current?.click();

    const onFilePicked = (e) => {
        const f = e.target.files?.[0];
        if (!f) return;
        validateAndSet(f);
    };

    const onDrop = (e) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragging(false);
        const f = e.dataTransfer.files?.[0];
        if (!f) return;
        validateAndSet(f);
    };

    const validateAndSet = (f) => {
        const ok = allowed.some((ext) => f.name.toLowerCase().endsWith(ext));
        if (!ok) {
            setError("Lütfen .xlsx veya .xls uzantılı bir dosya yükleyin.");
            setFile(null);
            return;
        }
        setError("");
        setFile(f);
    };

    const onDragOver = (e) => { e.preventDefault(); e.stopPropagation(); setIsDragging(true); };
    const onDragLeave = (e) => { e.preventDefault(); e.stopPropagation(); setIsDragging(false); };

    const reset = () => {
        setFile(null);
        setError("");
        if (inputRef.current) inputRef.current.value = "";
    };

    const formatSize = (bytes) => {
        if (bytes < 1024) return `${bytes} B`;
        if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
        return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
    };

    // Supabase’ten DÖKÜMAN verisini çek
    const fetchDokumanRows = async () => {
        const { data, error } = await supabase
            .from("Fiyat_Ekleme_Hesap_Adlari")
            .select("tip_id,detay_id,hizmet_adi,kdv_oran");

        if (error) throw error;

        // kdv_oran bazen "0,2" string olabilir → 0.2 sayıya çevir
        return (data || []).map((r) => ([
            r.tip_id ?? null,
            r.detay_id ?? null,
            r.hizmet_adi ?? "",
            typeof r.kdv_oran === "string"
                ? parseFloat(String(r.kdv_oran).replace(",", "."))
                : Number(r.kdv_oran ?? 0)
        ]));
    };

    // Excel (.xlsx) indir: ŞABLON + DÖKÜMAN (Supabase)
    const downloadTemplate = async () => {
        try {
            setDownloading(true);

            // 1) ŞABLON sayfası (sadece başlıklar)
            const S_HEADERS = [
                "SeferID", "Cari Unvan", "Hesap Adı",
                "Birim Fiyat", "Miktar", "KDV Oranı",
                "Tevkifat Oranı", "Açıklama"
            ];
            const sablonWS = XLSX.utils.aoa_to_sheet([S_HEADERS]);
            sablonWS["!cols"] = [
                { wch: 10 }, { wch: 28 }, { wch: 26 },
                { wch: 14 }, { wch: 10 }, { wch: 12 },
                { wch: 16 }, { wch: 44 },
            ];

            // 2) DÖKÜMAN sayfası (Supabase’ten)
            const rows = await fetchDokumanRows();
            const D_HEADERS = ["tip_id", "detay_id", "hizmet_adi", "kdv_oran"];
            const dokumanWS = XLSX.utils.aoa_to_sheet([D_HEADERS, ...rows]);
            dokumanWS["!cols"] = [{ wch: 8 }, { wch: 10 }, { wch: 46 }, { wch: 10 }];

            // kdv_oran’ı yüzde formatında göster (0.2 → %20)
            for (let r = 2; r <= rows.length + 1; r++) {
                const addr = "D" + r;
                const cell = dokumanWS[addr];
                if (cell && typeof cell.v === "number") {
                    cell.z = "0%";
                }
            }

            // 3) Kitabı yaz
            const wb = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(wb, sablonWS, "ŞABLON");
            XLSX.utils.book_append_sheet(wb, dokumanWS, "DÖKÜMAN");
            XLSX.writeFile(wb, "gelir_sablon.xlsx");
        } catch (err) {
            console.error(err);
            setError("DÖKÜMAN verisi alınamadı. Lütfen tekrar deneyin.");
        } finally {
            setDownloading(false);
        }
    };

    const upload = () => {
        if (!file) return;
        // const fd = new FormData(); fd.append("file", file);
        // await fetch("/api/gelir-yukle", { method: "POST", body: fd });
        alert(`Yüklendi: ${file.name}`);
        reset();
    };

    return (
        <div className="ge-page">
            <div className="ge-topbar">
                <div>
                    <h1>Gelir Ekleme</h1>
                    <p className="ge-sub">Excel ile toplu yükleme yap veya dosyayı sürükle-bırak.</p>
                </div>
                <div className="ge-top-actions">
                    <button className="btn ghost" onClick={downloadTemplate} disabled={downloading}>
                        {downloading ? "İndiriliyor…" : "Şablonu İndir (.xlsx)"}
                    </button>
                    <button className="btn" onClick={openPicker}>Dosya Seç</button>
                    <input
                        ref={inputRef}
                        type="file"
                        accept={[
                            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                            "application/vnd.ms-excel",
                            ".xlsx",
                            ".xls",
                        ].join(",")}
                        onChange={onFilePicked}
                        hidden
                    />
                </div>
            </div>

            <div
                className={`ge-drop ${isDragging ? "dragging" : ""}`}
                onDragOver={onDragOver}
                onDragLeave={onDragLeave}
                onDrop={onDrop}
                onClick={openPicker}
                role="button"
                tabIndex={0}
            >
                <div className="ge-drop-inner">
                    <div className="ge-icon">⬆️</div>
                    <div className="ge-title">Dosyanı buraya sürükle & bırak</div>
                    <div className="ge-muted">veya <span className="ge-link">bilgisayardan seç</span> (.xlsx, .xls)</div>
                </div>
            </div>

            {file && (
                <div className="ge-file">
                    <div className="ge-file-main">
                        <div className="ge-file-icon">📄</div>
                        <div>
                            <div className="ge-file-name">{file.name}</div>
                            <div className="ge-file-meta">{formatSize(file.size)}</div>
                        </div>
                    </div>
                    <button className="btn ghost danger" onClick={reset}>Kaldır</button>
                </div>
            )}

            {error && <div className="ge-error">{error}</div>}

            <div className="ge-bottombar">
                <div className="ge-bottombar-left">
                    {file ? <span>Yüklemeye hazır: <strong>{file.name}</strong></span> : <span>Henüz dosya seçilmedi</span>}
                </div>
                <div className="ge-bottombar-actions">
                    <button className="btn ghost" onClick={reset} disabled={!file}>Temizle</button>
                    <button className="btn" onClick={upload} disabled={!file}>Yükle</button>
                </div>
            </div>
        </div>
    );
}
